import Link from "next/link";
import { ArrowRight, ClipboardCheck, FileText, Receipt, Sparkles, Wrench } from "lucide-react";
import { redirect } from "next/navigation";
import { PropertyManagerPerkForm } from "@/src/components/vendor/property-manager-perk-form";
import { canAccessVendorDashboard } from "@/src/domain/vendor-memberships/entitlements";
import { canUsePropertyManagerPerk } from "@/src/domain/vendor-memberships/property-manager-perk";
import { getRoleHome } from "@/src/lib/auth/routing";
import { requireUser } from "@/src/lib/auth/session";
import { createSupabaseServerClient } from "@/src/lib/supabase/server";

export default async function VendorDashboardPage() {
  const user = await requireUser();
  const membership = user.memberships.find(item => item.organizationType === "vendor" && ["owner", "admin", "vendor", "technician"].includes(item.role));
  if (!membership || membership.organizationType !== "vendor" || !["owner", "admin", "vendor", "technician"].includes(membership.role)) redirect(getRoleHome(user));
  const supabase = await createSupabaseServerClient();
  const membershipPlan = await supabase.from("vendor_memberships").select("status,current_period_ends_at,vendor_membership_levels(code,name)").eq("vendor_organization_id",membership.organizationId).order("created_at",{ascending:false}).limit(1).maybeSingle();
  const currentPlan = membershipPlan.data?.vendor_membership_levels as unknown as {code:string;name:string}|null;
  const dashboardEligible = canAccessVendorDashboard({ code: currentPlan?.code, status: membershipPlan.data?.status, currentPeriodEndsAt: membershipPlan.data?.current_period_ends_at });
  if (!dashboardEligible) {
    const canManageMembership = ["owner", "admin", "vendor"].includes(membership.role);
    return <section className="mx-auto max-w-2xl rounded-[2rem] border border-slate-200 bg-white p-8 text-center shadow-sm sm:p-12"><Sparkles className="mx-auto size-10 text-emerald-700"/><h1 className="mt-5 text-3xl font-semibold tracking-tight">An active membership is required.</h1><p className="mt-3 text-sm leading-6 text-slate-600">Vendor dashboard access and property-management opportunities are available to active paid, complimentary, or manually granted members.</p>{canManageMembership?<Link href="/vendor/membership?error=membership_required" className="mt-6 inline-flex min-h-11 items-center rounded-full bg-slate-950 px-5 text-sm font-bold text-white">Choose a membership <ArrowRight className="ml-2 size-4"/></Link>:<p className="mt-6 text-sm font-semibold text-slate-700">Ask your organization owner or administrator to activate the membership.</p>}</section>;
  }
  const [opportunities, quotes, workOrders, invoices, profile, category] = await Promise.all([
    supabase.from("service_requests").select("id", { count: "exact", head: true }).in("status", ["open", "matching", "quoted"]),
    supabase.from("quotes").select("id", { count: "exact", head: true }).eq("vendor_organization_id", membership.organizationId).eq("status", "submitted"),
    supabase.from("work_orders").select("id", { count: "exact", head: true }).eq("vendor_organization_id", membership.organizationId).in("status", ["scheduled", "en_route", "on_site", "blocked"]),
    supabase.from("invoices").select("id", { count: "exact", head: true }).eq("vendor_organization_id", membership.organizationId).in("status", ["issued", "partially_paid", "overdue"]),
    supabase.from("vendor_profiles").select("lifecycle_status,approval_status,publication_status,property_manager_perk_enabled,property_manager_perk_title,property_manager_perk_description,property_manager_perk_type,property_manager_perk_terms,property_manager_perk_expiration_date").eq("organization_id", membership.organizationId).maybeSingle(),
    supabase.from("vendor_category_assignments").select("vendor_categories(name)").eq("vendor_organization_id", membership.organizationId).limit(1).maybeSingle(),
  ]);
  const metrics = [["Matched opportunities", opportunities.count ?? 0, ClipboardCheck], ["Open quotes", quotes.count ?? 0, FileText], ["Active work orders", workOrders.count ?? 0, Wrench], ["Outstanding invoices", invoices.count ?? 0, Receipt]] as const;
  const primaryCategory = category.data?.vendor_categories as unknown as {name:string}|null;
  const perk = profile.data;
  return <div>
    {profile.data?.publication_status!=="published"?<section className="mb-6 flex flex-col gap-4 rounded-2xl border border-amber-200 bg-amber-50 p-5 sm:flex-row sm:items-center sm:justify-between"><div><p className="font-bold text-amber-950">Marketplace profile: {profile.data?.lifecycle_status?.replaceAll("_"," ")??"onboarding"}</p><p className="mt-1 text-xs text-amber-900/75">Payment alone does not publish your listing. Complete the shared profile and approval workflow for any paid tier.</p></div><Link href="/vendor/profile" className="inline-flex min-h-10 items-center justify-center rounded-full bg-amber-900 px-4 text-xs font-black text-white">Complete profile <ArrowRight className="ml-2 size-4"/></Link></section>:null}
    <div className="flex flex-col gap-5 lg:flex-row lg:items-end lg:justify-between"><div><p className="text-sm font-semibold text-emerald-700">Local provider operations</p><h1 className="mt-1 text-3xl font-semibold tracking-[-.035em] text-slate-950 sm:text-4xl">Welcome to {membership.organizationName}.</h1><p className="mt-2 text-sm text-slate-500">Manage opportunities, quotes, field work, and payments from one Connect workspace.</p></div><Link href="/vendor/membership" className="flex min-w-64 items-center justify-between rounded-2xl bg-slate-950 p-4 text-white hover:bg-emerald-800"><span className="flex items-center gap-3"><span className="grid size-9 place-items-center rounded-xl bg-white/10"><Sparkles className="size-4 text-emerald-400"/></span><span><span className="block text-[10px] font-black uppercase tracking-wider text-slate-400">Marketplace membership</span><span className="mt-1 block text-sm font-bold">{currentPlan?.name??"Free"}</span></span></span><ArrowRight className="size-4"/></Link></div>
    <section aria-label="Provider actions" className="mt-6 grid gap-3 sm:grid-cols-2 xl:grid-cols-4"><Link href="/marketplace" className="rounded-2xl bg-emerald-50 p-4 transition hover:bg-emerald-100"><p className="text-sm font-bold text-emerald-900">New leads</p><p className="mt-1 text-xs leading-5 text-emerald-800/75">Review the local marketplace and current opportunities.</p></Link><Link href="/vendor/membership" className="rounded-2xl border border-slate-200 bg-white p-4 transition hover:border-emerald-300"><p className="text-sm font-bold text-slate-900">Membership</p><p className="mt-1 text-xs leading-5 text-slate-500">Review visibility, verification, and growth tools.</p></Link><Link href="/marketplace" className="rounded-2xl border border-slate-200 bg-white p-4 transition hover:border-emerald-300"><p className="text-sm font-bold text-slate-900">Profile visibility</p><p className="mt-1 text-xs leading-5 text-slate-500">See how your marketplace presence appears to teams.</p></Link><Link href="/impact" className="rounded-2xl border border-slate-200 bg-white p-4 transition hover:border-emerald-300"><p className="text-sm font-bold text-slate-900">Analytics</p><p className="mt-1 text-xs leading-5 text-slate-500">Review measured outcomes when records are available.</p></Link></section>
    <section className="mt-8 grid gap-4 sm:grid-cols-2 xl:grid-cols-4">{metrics.map(([label, value, Icon]) => <article key={label} className="rounded-2xl border border-slate-200 bg-white p-5 shadow-sm"><div className="flex justify-between"><div><p className="text-sm text-slate-500">{label}</p><p className="mt-3 text-3xl font-bold">{value.toLocaleString()}</p></div><span className="grid size-10 place-items-center rounded-xl bg-emerald-50"><Icon className="size-5 text-emerald-700" /></span></div></article>)}</section>
    <PropertyManagerPerkForm eligible={canUsePropertyManagerPerk(currentPlan?.code,membershipPlan.data?.status)} category={primaryCategory?.name ?? null} perk={{ enabled: perk?.property_manager_perk_enabled ?? false, title: perk?.property_manager_perk_title ?? null, description: perk?.property_manager_perk_description ?? null, type: perk?.property_manager_perk_type ?? null, terms: perk?.property_manager_perk_terms ?? null, expirationDate: perk?.property_manager_perk_expiration_date ?? null }} />
  </div>;
}
